examples.fromCode:
function combine(str1, str2) {
    return str1 + " " + str2;
}

examples.toCode:
#include <stdio.h>
#include <string.h>
#include <stdlib.h>

char* combine(const char* str1, const char* str2) {
    char* res = malloc(strlen(str1) + strlen(str2) + 2);
    if (res) {
        strcpy(res, str1);
        strcat(res, " ");
        strcat(res, str2);
    }
    return res;
}

