function total(arr) {
    return arr.reduce((sum, val) => sum + val, 0);
}

examples.toCode:
#include <stddef.h>

int total(const int* arr, size_t size) {
    int sum = 0;
    for (size_t i = 0; i < size; i++) {
        sum += arr[i];
    }
    return sum;
}
